<template>
  <h1>Dice Roller</h1>
  <b-button variant="primary" @click="rollDice">Roll dice</b-button>
  <br />
  <div class="dice">
    <die-component :value="dice[0].value" />
    <die-component :value="dice[1].value" />
    <die-component :value="dice[2].value" :drama="true" />
  </div>
  <br />
  <span>Total: {{ dice[0].value + dice[1].value + dice[2].value }}</span>
  <p v-if="hasStunts()">Stunt points: {{ stuntPoints }}</p>
  <div v-if="hasStunts()">
    <div v-for="(table, index) in stuntTables" :key="index">
      <hr />
      <b-button
        squared
        v-on:click="toggleCollapse(`collapse-${index}`)"
        variant="primary"
        class="table-title"
      >
        <b>{{ table.title }}</b>
      </b-button>
      <b-collapse :id="'collapse-' + index" :visible="index === 0">
        <table v-if="hasStunts()">
          <tr>
            <th>SP Cost</th>
            <th>Stunt</th>
          </tr>
          <tr
            v-for="(stunt, index) in table.stunts.filter(
              (s) => s.cost <= stuntPoints
            )"
            :key="index"
          >
            <td style="text-align: center">
              {{ stunt?.costLabel || stunt.cost }}
            </td>
            <td v-html="stunt.description"></td>
          </tr>
        </table>
      </b-collapse>
    </div>
  </div>
</template>

<script>
import DieComponent from "@/components/DieComponent.vue";
import stunt_table_json from "@/assets/stunt_tables.json";

export default {
  components: {
    DieComponent,
  },
  data() {
    return {
      dice: [{ value: 6 }, { value: 6 }, { value: 6 }],
      stuntPoints: 0,
      stuntTables: stunt_table_json,
    };
  },
  methods: {
    hasStunts() {
      let self = this;
      return (
        self.dice[0].value === self.dice[1].value ||
        self.dice[1].value === self.dice[2].value ||
        self.dice[0].value === self.dice[2].value
      );
    },
    getStuntPoints() {
      let self = this;
      if (self.hasStunts()) return self.dice[2].value;
      else return 0;
    },
    rollDice() {
      let self = this;
      self.dice.forEach((die) => {
        die.value = Math.floor(Math.random() * 6) + 1;
      });
      self.stuntPoints = this.getStuntPoints();
    },
    toggleCollapse(id) {
      const element = document.getElementById(id);
      const classes = `${element.classList}`.split(" ");
      if (classes.includes("show")) {
        element.classList.remove("show");
      } else {
        element.classList.add("show");
      }
    },
  },
  mounted() {
    this.rollDice();
  },
};
</script>

